// GABRIEL Overnight Market Data Collector v2.0
// Fetches 15 symbols from Yahoo Finance v8
const symbols = [
  'ES=F',    // S&P 500 futures
  'NQ=F',    // Nasdaq futures
  'YM=F',    // Dow futures
  'RTY=F',   // Russell 2000 futures
  'GC=F',    // Gold futures
  'SI=F',    // Silver futures — primary thesis
  'CL=F',    // Crude oil futures
  '%5EVIX',  // VIX (encoded ^VIX)
  'BTC-USD', // Bitcoin (IBIT proxy)
  'ETH-USD', // Ethereum
  'UUP',     // DXY proxy ETF
  'TLT',     // Long bond proxy (inverse yield)
  'DIA',     // Dow ETF (after-hours proxy)
  'SPY',     // S&P ETF (after-hours proxy)
  'QQQ'      // Nasdaq ETF (after-hours proxy)
];

const marketData = {};

for (const sym of symbols) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://query1.finance.yahoo.com/v8/finance/chart/${sym}?interval=1d&range=2d`,
      headers: { 'User-Agent': 'Mozilla/5.0 (GABRIEL/2.0)' },
      json: true
    });
    const meta = resp?.chart?.result?.[0]?.meta;
    if (!meta) continue;
    const price = meta.regularMarketPrice || 0;
    const prevClose = meta.chartPreviousClose || 0;
    const changePct = prevClose > 0 ? Math.round(((price - prevClose) / prevClose) * 10000) / 100 : 0;
    const cleanSym = (meta.symbol || sym).replace('%5E', '^').replace('^', '');
    marketData[cleanSym] = {
      lastPrice: price,
      changePercent: changePct,
      previousClose: prevClose,
      symbol: cleanSym
    };
  } catch (e) {
    // Symbol fetch failed — skip, do not halt workflow
    marketData[sym.replace('%5E', '').replace('^', '')] = { lastPrice: 0, changePercent: 0, previousClose: 0, error: true };
  }
}

return [{ json: {
  market_data: marketData,
  symbol_count: Object.keys(marketData).length,
  fetch_time: new Date().toISOString(),
  source: 'YAHOO_FINANCE_V8'
}}];

// GABRIEL News Scanner v2.0
// Scans Finnhub general news for geopolitical keywords
const FINNHUB_KEY = ''; // ADD: Pull from HUNTER H30 credential in n8n

const keywords = [
  'hormuz', 'strait', 'iran', 'nuclear', 'ceasefire',
  'margin call', 'circuit breaker', 'force majeure', 'default',
  'fed rate', 'emergency meeting', 'black swan', 'oil embargo',
  'opec emergency', 'strategic reserve', 'bank run', 'sanctions'
];

const criticalKeywords = ['nuclear', 'circuit breaker', 'force majeure', 'default', 'emergency meeting', 'bank run'];

const input = $input.first().json;
const alerts = [];
let newsFetchOk = false;

try {
  const newsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://finnhub.io/api/v1/news?category=general&token=${FINNHUB_KEY}`,
    json: true
  });
  newsFetchOk = true;
  const articles = Array.isArray(newsResp) ? newsResp.slice(0, 50) : [];
  for (const article of articles) {
    const text = ((article.headline || '') + ' ' + (article.summary || '')).toLowerCase();
    for (const kw of keywords) {
      if (text.includes(kw)) {
        alerts.push({
          type: criticalKeywords.includes(kw) ? 'NEWS_CRITICAL' : 'NEWS_KEYWORD',
          keyword: kw,
          headline: article.headline || '',
          source: article.source || '',
          url: article.url || '',
          timestamp: article.datetime ? new Date(article.datetime * 1000).toISOString() : new Date().toISOString()
        });
        break;
      }
    }
  }
} catch (e) {
  // Finnhub unavailable — continue with empty alerts, do not fail
}

return [{ json: {
  market_data: input.market_data,
  news_alerts: alerts,
  news_count: alerts.length,
  news_fetch_ok: newsFetchOk,
  fetch_time: input.fetch_time
}}];

// GABRIEL Threshold Engine v2.0
// Evaluates GREEN / YELLOW / RED escalation
const input = $input.first().json;
const md = input.market_data || {};
const newsAlerts = input.news_alerts || [];

const yellowTriggers = [];
const redTriggers = [];

function chkY(sym, threshold, label) {
  if (md[sym] && Math.abs(md[sym].changePercent) > threshold) {
    yellowTriggers.push({ symbol: sym, value: md[sym].changePercent, threshold, label });
  }
}

function chkR(sym, threshold, label) {
  if (md[sym] && Math.abs(md[sym].changePercent) > threshold) {
    redTriggers.push({ symbol: sym, value: md[sym].changePercent, threshold, label });
  }
}

// YELLOW checks
chkY('ES=F',    1.0,  'S&P 500 futures > 1%');
chkY('VIX',    15.0,  'VIX change > 15%');
chkY('CL=F',    3.0,  'Crude oil > 3%');
chkY('GC=F',    2.0,  'Gold > 2%');
chkY('SI=F',    5.0,  'Silver > 5% — THESIS ALERT');
chkY('UUP',     0.5,  'DXY proxy > 0.5% — correlation risk');
chkY('BTC-USD', 5.0,  'Bitcoin > 5%');

// VIX absolute level YELLOW
if (md['VIX'] && md['VIX'].lastPrice > 25) {
  yellowTriggers.push({ symbol: 'VIX', value: md['VIX'].lastPrice, threshold: 25, label: 'VIX level > 25' });
}

// RED checks
chkR('ES=F',    3.0,  'S&P 500 futures > 3% — regime shift');
chkR('CL=F',    8.0,  'Crude oil > 8% — Hormuz-class event');
chkR('SI=F',   10.0,  'Silver > 10% — MARGIN CALL TERRITORY');
chkR('UUP',     1.5,  'DXY > 1.5% — Kill Switch warning');

// VIX absolute RED
if (md['VIX'] && md['VIX'].lastPrice > 35) {
  redTriggers.push({ symbol: 'VIX', value: md['VIX'].lastPrice, threshold: 35, label: 'VIX > 35 — CRISIS' });
}

// Multi-signal: 3+ yellows = RED
if (yellowTriggers.length >= 3) {
  redTriggers.push({ symbol: 'MULTI', value: yellowTriggers.length, threshold: 3, label: `${yellowTriggers.length} simultaneous yellow triggers — coordinated selloff` });
}

// News escalation
if (newsAlerts.length > 0) {
  yellowTriggers.push({ symbol: 'NEWS', value: newsAlerts.length, threshold: 1, label: `${newsAlerts.length} news keyword alert(s)` });
  for (const alert of newsAlerts) {
    if (alert.type === 'NEWS_CRITICAL') {
      redTriggers.push({ symbol: 'NEWS_CRITICAL', value: alert.keyword, threshold: 0, label: `CRITICAL: ${alert.keyword} — ${alert.headline.substring(0, 60)}` });
    }
  }
}

// Kill Switch pre-alert
const ksWarning = (
  md['UUP'] && md['UUP'].changePercent > 0.3 &&
  md['TLT'] && md['TLT'].changePercent < -0.3 &&
  md['VIX'] && md['VIX'].lastPrice > 30
);

if (ksWarning) {
  redTriggers.push({ symbol: 'KILLSWITCH', value: 'DXY+YIELDS+VIX', threshold: 0, label: 'KILL SWITCH PRE-ALERT: DXY rising + yields rising + VIX > 30' });
}

const escalation = redTriggers.length > 0 ? 'RED' : (yellowTriggers.length > 0 ? 'YELLOW' : 'GREEN');

return [{ json: {
  escalation,
  yellow_triggers: yellowTriggers,
  red_triggers: redTriggers,
  yellow_count: yellowTriggers.length,
  red_count: redTriggers.length,
  kill_switch_warning: !!ksWarning,
  market_data: md,
  news_alerts: newsAlerts,
  timestamp: new Date().toISOString()
}}];

// GABRIEL Report Builder v2.0
// Builds HTML-formatted Telegram message
const input = $input.first().json;
const md = input.market_data || {};
const esc = input.escalation;

const emojiMap = { RED: '🚨', YELLOW: '⚠️', GREEN: '✅' };
const emoji = emojiMap[esc] || '✅';
const now = new Date();
const etTime = now.toLocaleTimeString('en-US', { timeZone: 'America/New_York', hour: '2-digit', minute: '2-digit' });
const dateStr = now.toISOString().substring(0, 10);

let msg = `${emoji} <b>GABRIEL OVERNIGHT WATCH</b>\n`;
msg += `<i>${dateStr} | ${etTime} ET | ${esc}</i>\n\n`;

// Market snapshot
const displayOrder = [
  ['ES=F','S&P Futs'], ['NQ=F','NQ Futs'], ['VIX','VIX'],
  ['CL=F','Oil'], ['GC=F','Gold'], ['SI=F','Silver'],
  ['UUP','DXY(UUP)'], ['TLT','Bonds(TLT)'], ['BTC-USD','BTC']
];
msg += '<b>MARKET SNAPSHOT</b>\n';
for (const [sym, label] of displayOrder) {
  const d = md[sym];
  if (d && d.lastPrice) {
    const arrow = d.changePercent > 0 ? '▲' : (d.changePercent < 0 ? '▼' : '━');
    const chg = (d.changePercent >= 0 ? '+' : '') + d.changePercent.toFixed(2) + '%';
    msg += `${label}: ${d.lastPrice.toFixed(2)} ${arrow} ${chg}\n`;
  }
}

// Red triggers
if (input.red_triggers && input.red_triggers.length > 0) {
  msg += '\n🚨 <b>RED TRIGGERS</b>\n';
  for (const t of input.red_triggers) msg += `• ${t.label}\n`;
}

// Yellow triggers
if (input.yellow_triggers && input.yellow_triggers.length > 0) {
  msg += `\n⚠️ <b>YELLOW TRIGGERS (${input.yellow_count})</b>\n`;
  for (const t of input.yellow_triggers) msg += `• ${t.label}\n`;
}

// News alerts
if (input.news_alerts && input.news_alerts.length > 0) {
  msg += `\n📰 <b>NEWS ALERTS (${input.news_alerts.length})</b>\n`;
  for (const n of input.news_alerts.slice(0, 5)) {
    msg += `• [${n.keyword.toUpperCase()}] ${n.headline.substring(0, 75)}\n`;
  }
}

// Kill Switch warning
if (input.kill_switch_warning) {
  msg += '\n🔴 <b>KILL SWITCH PRE-ALERT</b>\n';
  msg += 'DXY ▲ + Yields ▲ + VIX &gt; 30\n';
  msg += 'Correlation Kill Switch conditions forming.\n';
  msg += 'Review metals positions BEFORE 9:30 AM open.\n';
}

// Footer
msg += `\n<i>GABRIEL v2.0 | Uriel Covenant</i>`;

return [{ json: {
  telegram_message: msg,
  escalation: esc,
  timestamp: input.timestamp,
  market_data: md,
  triggers: { yellow: input.yellow_triggers, red: input.red_triggers },
  news_alerts: input.news_alerts,
  kill_switch_warning: input.kill_switch_warning,
  yellow_count: input.yellow_count,
  red_count: input.red_count
}}];

// GABRIEL Logger v2.0 — Supabase
const SUPABASE_PROJECT = 'bwtguoaakkmsnzomswem';
const SUPABASE_ANON_KEY = 'sb_publishable_is2iGeR-YRuNrhdsvrr3-w_PVAFcm8z';

const input = $input.first().json;

function uuid4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const entry = {
  id: uuid4(),
  escalation: input.escalation || 'GREEN',
  yellow_count: input.yellow_count || 0,
  red_count: input.red_count || 0,
  news_count: (input.news_alerts || []).length,
  kill_switch_warning: input.kill_switch_warning || false,
  market_snapshot: input.market_data ? JSON.stringify(input.market_data) : '{}',
  timestamp: input.timestamp || new Date().toISOString()
};

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://${SUPABASE_PROJECT}.supabase.co/rest/v1/gabriel_overnight_log`,
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: entry,
    json: true
  });
} catch (e) {
  // Log write failed — do not fail workflow
}

return [{ json: { logged: true, escalation: entry.escalation, id: entry.id, timestamp: entry.timestamp } }];

// GABRIEL Morning Brief Builder v2.0
// Queries Supabase for overnight logs, synthesizes into report
const SUPABASE_PROJECT = 'bwtguoaakkmsnzomswem';
const SUPABASE_ANON_KEY = 'sb_publishable_is2iGeR-YRuNrhdsvrr3-w_PVAFcm8z';

// Get last 12 hours of logs
const since = new Date(Date.now() - 12 * 60 * 60 * 1000).toISOString();
let logs = [];
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://${SUPABASE_PROJECT}.supabase.co/rest/v1/gabriel_overnight_log?timestamp=gte.${since}&order=timestamp.desc`,
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
    },
    json: true
  });
  logs = Array.isArray(resp) ? resp : [];
} catch (e) { /* continue with empty */ }

// Stats
const total = logs.length;
const reds = logs.filter(l => l.escalation === 'RED').length;
const yellows = logs.filter(l => l.escalation === 'YELLOW').length;
const greens = logs.filter(l => l.escalation === 'GREEN').length;
const ksAlerts = logs.filter(l => l.kill_switch_warning).length;
const maxRed = logs.reduce((m, l) => Math.max(m, l.red_count || 0), 0);
const maxYellow = logs.reduce((m, l) => Math.max(m, l.yellow_count || 0), 0);

// Market posture logic
let posture = 'RISK-ON';
if (reds > 0 || ksAlerts > 0) posture = 'RISK-OFF';
else if (yellows > 2) posture = 'NEUTRAL';

// Pull latest market data fresh
let freshData = {};
const quickSyms = ['ES=F', 'SI=F', 'GC=F', 'CL=F', '%5EVIX', 'UUP'];
for (const sym of quickSyms) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://query1.finance.yahoo.com/v8/finance/chart/${sym}?interval=1d&range=1d`,
      headers: { 'User-Agent': 'Mozilla/5.0' },
      json: true
    });
    const meta = r?.chart?.result?.[0]?.meta;
    if (meta) {
      const clean = (meta.symbol || sym).replace('%5E','').replace('^','');
      freshData[clean] = {
        lastPrice: meta.regularMarketPrice || 0,
        changePercent: meta.regularMarketDayHigh ? Math.round(((meta.regularMarketPrice - meta.chartPreviousClose) / meta.chartPreviousClose) * 10000) / 100 : 0
      };
    }
  } catch (e) {}
}

// Build message
const postureEmoji = { 'RISK-ON': '🟢', 'NEUTRAL': '🟡', 'RISK-OFF': '🔴' };
const etTime = new Date().toLocaleTimeString('en-US', { timeZone: 'America/New_York', hour: '2-digit', minute: '2-digit' });
const dateStr = new Date().toISOString().substring(0, 10);

let msg = `🌅 <b>GABRIEL MORNING BRIEF</b>\n`;
msg += `<i>${dateStr} | ${etTime} ET</i>\n\n`;
msg += `${postureEmoji[posture]} <b>POSTURE: ${posture}</b>\n\n`;
msg += `<b>OVERNIGHT SUMMARY (last 12h)</b>\n`;
msg += `Runs: ${total} | 🚨 RED: ${reds} | ⚠️ YELLOW: ${yellows} | ✅ GREEN: ${greens}\n`;
if (ksAlerts > 0) msg += `🔴 Kill Switch pre-alerts: ${ksAlerts}\n`;
if (maxRed > 0) msg += `Peak red triggers in single run: ${maxRed}\n`;

// Fresh pre-market snapshot
const snapLabels = {'ES=F':'S&P Futs', 'SI=F':'Silver', 'GC=F':'Gold', 'CL=F':'Oil', 'VIX':'VIX', 'UUP':'DXY(UUP)'};
msg += '\n<b>PRE-MARKET NOW</b>\n';
for (const [sym, label] of Object.entries(snapLabels)) {
  const d = freshData[sym.replace('=F','=F').replace('%5E','')];
  if (d && d.lastPrice) {
    const arrow = d.changePercent > 0 ? '▲' : (d.changePercent < 0 ? '▼' : '━');
    msg += `${label}: ${d.lastPrice.toFixed(2)} ${arrow} ${d.changePercent >= 0 ? '+' : ''}${d.changePercent.toFixed(2)}%\n`;
  }
}

if (reds > 0 || ksAlerts > 0) {
  msg += '\n⚡ <b>ACTION REQUIRED</b>\n';
  msg += 'RED events occurred overnight. Review SENTINEL stops before open.\n';
  msg += 'Check Telegram history for full RED alert details.\n';
}

msg += `\n<i>SENTINEL activates 9:30 AM ET. GABRIEL signing off.</i>`;

return [{ json: { morning_brief_message: msg, posture, overnight_stats: { total, reds, yellows, greens, ksAlerts }, timestamp: new Date().toISOString() } }];
